// Best-effort partial proof. With the real (closed) type definitions,
    // proving `r1 == r2` from same-view preconditions is impossible without
    // forbidden constructs: `Vec<K>` SMT-equality is *not* determined by the
    // view (`@`) of the vector — two empty vectors can differ at the SMT
    // level. See the discussion in /tmp/vec_test*.rs experiments: the
    // postcondition `a.len()==0 && b.len()==0 && a@==b@ ==> a==b` fails on
    // bare `Vec<u8>`. Since `StrictlyOrderedMap` contains `keys.v: Vec<K>`
    // and `vals: Vec<ID>`, structural equality cannot be derived without
    // axioms. We keep the strongest view-level derivations as documentation
    // of effort.
    if r1.valid() && r1@ == Map::<K,ID>::empty() && r2.valid() && r2@ == Map::<K,ID>::empty() {
        reveal(StrictlyOrderedMap::valid);
        reveal(StrictlyOrderedMap::map_valid);
        reveal(StrictlyOrderedVec::valid);
        reveal(StrictlyOrderedMap::view);
        reveal(StrictlyOrderedVec::view);
        assert(r1.m@.dom() =~= Set::<K>::empty());
        assert(r1.keys@.to_set() =~= Set::<K>::empty());
        assert(r2.keys@.to_set() =~= Set::<K>::empty());
        if r1.keys@.len() > 0 {
            assert(r1.keys@.to_set().contains(r1.keys@[0]));
            assert(false);
        }
        if r2.keys@.len() > 0 {
            assert(r2.keys@.to_set().contains(r2.keys@[0]));
            assert(false);
        }
        assert(r1.keys@.len() == 0);
        assert(r2.keys@.len() == 0);
        assert(r1.keys@ =~= r2.keys@);
        assert(r1.vals@.len() == 0);
        assert(r2.vals@.len() == 0);
        assert(r1.vals@ =~= r2.vals@);
        assert(r1.m@ =~= r2.m@);
        assert(r1 =~~= r2);
    }
